const QUESTIONS = [
 {id:"fn1",topic:"Functions",difficulty:"Warm-up",type:"mc",prompt:"If f(x) = 3x − 4, what is f(5)?",choices:["8","11","15","19"],answer:"11",lesson:"Function notation is a substitution instruction. Replace every x with the input. Example: if g(x)=2x+1, then g(4)=2(4)+1=9. For this problem, substitute 5 for x.",explanation:"f(5)=3(5)−4=11.",mistake:"Substitution error"},
 {id:"fn2",topic:"Functions",difficulty:"Medium",type:"mc",prompt:"Compared with y = x², how is y = (x − 3)² + 2 transformed?",choices:["Left 3, down 2","Right 3, up 2","Right 2, up 3","Left 2, down 3"],answer:"Right 3, up 2",lesson:"In y=(x−h)²+k, h moves the graph horizontally (opposite the sign you see) and k moves it vertically. Example: (x+4)²−1 goes left 4 and down 1.",explanation:"The −3 inside shifts right 3; +2 outside shifts up 2.",mistake:"Misread transformation"},
 {id:"q1",topic:"Quadratics",difficulty:"Warm-up",type:"mc",prompt:"What are the solutions to x² − 5x + 6 = 0?",choices:["1 and 6","2 and 3","−2 and −3","0 and 6"],answer:"2 and 3",lesson:"To factor x²+bx+c, find two numbers that multiply to c and add to b. Example: x²−7x+12=(x−3)(x−4), so x=3 or 4.",explanation:"(x−2)(x−3)=0, so x=2 or x=3.",mistake:"Factoring error"},
 {id:"q2",topic:"Quadratics",difficulty:"Honors",type:"text",prompt:"For 2x² − 5x + 7 = 0, how many real solutions are there?",answer:["0","zero","no real solutions","none"],lesson:"Use the discriminant b²−4ac. Positive means 2 real roots, zero means 1, and negative means no real roots. Example: x²+2x+5 has 4−20<0, so no real roots.",explanation:"The discriminant is (−5)²−4(2)(7)=−31, so there are 0 real solutions.",mistake:"Discriminant error"},
 {id:"c1",topic:"Complex Numbers",difficulty:"Medium",type:"mc",prompt:"Simplify i¹⁸.",choices:["1","−1","i","−i"],answer:"−1",lesson:"Powers of i repeat every four: i, −1, −i, 1. Divide the exponent by 4 and use the remainder. 10 leaves remainder 2, so i¹⁰=i²=−1.",explanation:"18 leaves remainder 2 when divided by 4, so i¹⁸=i²=−1.",mistake:"Power cycle error"},
 {id:"p1",topic:"Polynomials",difficulty:"Medium",type:"mc",prompt:"What is the remainder when p(x)=x³−2x+5 is divided by x−2?",choices:["1","5","7","9"],answer:"9",lesson:"The Remainder Theorem says the remainder after dividing p(x) by x−a is p(a). Example: for x²+1 divided by x−3, the remainder is 3²+1=10.",explanation:"p(2)=8−4+5=9.",mistake:"Evaluation error"},
 {id:"p2",topic:"Polynomials",difficulty:"Honors",type:"tf",prompt:"True or false: A zero with even multiplicity makes a polynomial graph cross the x-axis.",choices:["True","False"],answer:"False",lesson:"At odd-multiplicity zeros, a graph crosses the axis. At even-multiplicity zeros, it touches and turns. Think of y=x² touching at zero versus y=x³ crossing.",explanation:"False. Even multiplicity touches and turns; odd multiplicity crosses.",mistake:"Multiplicity confusion"},
 {id:"r1",topic:"Rational Functions",difficulty:"Medium",type:"mc",prompt:"Simplify (x² − 9)/(x − 3), where x ≠ 3.",choices:["x − 3","x + 3","x² + 3","1"],answer:"x + 3",lesson:"Factor before canceling. A difference of squares a²−b²=(a−b)(a+b). Example: (x²−16)/(x−4)=x+4, while x=4 remains excluded.",explanation:"Factor as (x−3)(x+3), then cancel x−3. The restriction x≠3 remains.",mistake:"Domain restriction"},
 {id:"r2",topic:"Rational Functions",difficulty:"Honors",type:"mc",prompt:"What feature does f(x)=(x−2)/((x−2)(x+1)) have at x=2?",choices:["Vertical asymptote","Hole","x-intercept","No special feature"],answer:"Hole",lesson:"A factor that cancels creates a hole at its zero. A denominator factor that remains creates a vertical asymptote. Example: (x−4)/((x−4)(x+2)) has a hole at x=4.",explanation:"The x−2 factor cancels, so x=2 is a hole.",mistake:"Asymptote/hole confusion"},
 {id:"rad1",topic:"Radicals",difficulty:"Medium",type:"mc",prompt:"Simplify √72.",choices:["6√2","12√6","8√9","3√8"],answer:"6√2",lesson:"Look for the largest perfect-square factor. Example: √50=√(25·2)=5√2. Here, find a perfect square inside 72.",explanation:"72=36·2, so √72=6√2.",mistake:"Radical simplification"},
 {id:"e1",topic:"Exponential Functions",difficulty:"Warm-up",type:"text",prompt:"Solve 3 · 2ˣ = 48.",answer:["4","x=4","x = 4"],lesson:"Isolate the exponential expression, then match powers with the same base. Example: 5·3ˣ=135 gives 3ˣ=27=3³, so x=3.",explanation:"Divide by 3: 2ˣ=16=2⁴, so x=4.",mistake:"Exponent rule error"},
 {id:"log1",topic:"Logarithms",difficulty:"Medium",type:"mc",prompt:"Rewrite log₂(32)=5 in exponential form.",choices:["5²=32","2⁵=32","32²=5","2³²=5"],answer:"2⁵=32",lesson:"logₐ(b)=c means aᶜ=b. The base stays the base. Example: log₃(81)=4 becomes 3⁴=81.",explanation:"The base 2 raised to the exponent 5 equals 32.",mistake:"Log form confusion"},
 {id:"s1",topic:"Sequences",difficulty:"Warm-up",type:"text",prompt:"Find the 8th term of the arithmetic sequence 5, 8, 11, …",answer:["26","a8=26","a₈=26"],lesson:"For an arithmetic sequence, aₙ=a₁+(n−1)d. Example: 2,7,12,… has a₆=2+5(5)=27.",explanation:"a₈=5+(8−1)(3)=26.",mistake:"Sequence formula error"},
 {id:"sys1",topic:"Systems",difficulty:"Medium",type:"mc",prompt:"Solve: y=2x+1 and y=−x+7.",choices:["(2, 5)","(3, 7)","(1, 3)","(4, 9)"],answer:"(2, 5)",lesson:"At an intersection, both y-expressions are equal. Set them equal, solve for x, then substitute. Example: y=x+2 and y=−x+6 gives x=2, y=4.",explanation:"2x+1=−x+7 gives x=2 and y=5.",mistake:"System substitution error"},
 {id:"t1",topic:"Trigonometry",difficulty:"Honors",type:"mc",prompt:"Convert 150° to radians.",choices:["π/6","5π/6","3π/2","5π/3"],answer:"5π/6",lesson:"Multiply degrees by π/180 and simplify. Example: 60°·π/180=π/3.",explanation:"150·π/180=5π/6.",mistake:"Degree/radian conversion"}
];
