function shuffle(a){return [...a].sort(()=>Math.random()-.5)}
function grade(p){return p>=93?"A":p>=90?"A−":p>=87?"B+":p>=83?"B":p>=80?"B−":p>=77?"C+":p>=73?"C":p>=70?"C−":p>=60?"Needs review":"Reteach needed"}
