function cleanGeneratedQuestion(topic,q,seed){if(topic==="Exponential Functions"&&/log/i.test(`${q.prompt} ${q.lesson} ${q.explanation}`)){q=generatedTopicQuestion(topic,seed+41,q.difficulty)}q.id=`${q.id}-${Math.floor(Math.random()*100000)}`;return q}
function chooseTopicQuestions(topic,count,difficulty,options={}){data=shapeData(data);let remember=options.remember!==false,used=new Set(data.generatorLog.usedPromptKeys),picked=[],pickedKeys=new Set(),seed=(++data.generatorLog.sessionCounter*97)+(Date.now()%997)+Math.floor(Math.random()*997),limit=Math.max(2400,count*220);for(let tries=0;picked.length<count&&tries<limit;tries++){let q=cleanGeneratedQuestion(topic,generatedTopicQuestion(topic,seed+tries*3,difficulty),seed+tries*3),key=questionKey(q);if(!pickedKeys.has(key)&&!used.has(key)){picked.push(q);pickedKeys.add(key)}}for(let tries=0;picked.length<count&&tries<limit;tries++){let q=cleanGeneratedQuestion(topic,generatedTopicQuestion(topic,seed+tries*5+13,difficulty),seed+tries*5+13),key=questionKey(q);if(!pickedKeys.has(key)){picked.push(q);pickedKeys.add(key)}}for(let tries=0;picked.length<count&&tries<limit;tries++){let q=cleanGeneratedQuestion(topic,generatedTopicQuestion(topic,seed+tries*11+503,difficulty),seed+tries*11+503),key=questionKey(q);if(!pickedKeys.has(key)){picked.push(q);pickedKeys.add(key)}}while(picked.length<count){let q=cleanGeneratedQuestion(topic,generatedTopicQuestion(topic,seed+picked.length*17+5003,difficulty),seed+picked.length*17+5003);picked.push(q)}if(remember)rememberQuestionSet(picked);return picked}
function chooseUnitQuestions(topic,count){let levels=["Warm-up","Easy","Medium","Honors"],picked=[],seen=new Set(),tries=0;while(picked.length<count&&tries<count*60+240){let level=levels[tries%levels.length],q=chooseTopicQuestions(topic,1,level,{remember:false})[0],key=questionKey(q);if(!seen.has(key)){picked.push(q);seen.add(key)}tries++}while(picked.length<count){let level=levels[picked.length%levels.length],q=chooseTopicQuestions(topic,1,level,{remember:false})[0];picked.push(q)}rememberQuestionSet(picked);return picked}
function validPositiveInteger(value){return Number.isInteger(Number(value))&&Number(value)>0}
