function answerText(q){return Array.isArray(q.answer)?q.answer[0]:q.answer}
function renderWorksheet(w){$("#worksheetPaper").innerHTML=`<div class="worksheet-head"><p class="kicker">ALGEBRA 2 GLOW-UP</p><h1>${escapeHtml(w.title)}</h1><div class="worksheet-meta"><span>Name: ____________________</span><span>Date: ____________________</span><span>${escapeHtml(w.count)} questions</span><span>Difficulty: ${escapeHtml(w.difficulty)}</span></div><p>Show your work. Circle or write your final answer clearly.</p></div><ol class="worksheet-list">${w.questions.map(q=>`<li><div class="worksheet-topic">${escapeHtml(q.topic)} • ${escapeHtml(q.difficulty)}</div><p>${escapeHtml(q.prompt)}</p>${q.type!=="text"?`<div class="worksheet-choices">${q.choices.map((c,i)=>`<span>${String.fromCharCode(65+i)}. ${escapeHtml(c)}</span>`).join("")}</div>`:""}<div class="answer-lines"><span></span><span></span></div></li>`).join("")}</ol><section class="answer-key"><h2>Answer key</h2><ol>${w.questions.map(q=>`<li>${escapeHtml(answerText(q))}</li>`).join("")}</ol></section>`}
function renderQuestion(){let q=exam.questions[exam.index],a=exam.answers[q.id];$("#questionTopic").textContent=q.topic;$("#questionDifficulty").textContent=q.difficulty;$("#questionType").textContent=q.type==="mc"?"MULTIPLE CHOICE":q.type==="tf"?"TRUE OR FALSE":"SHORT ANSWER";$("#questionPrompt").textContent=q.prompt;let area=$("#answerArea");if(q.type==="text")area.innerHTML=`<label><span class="kicker">YOUR ANSWER</span><input class="answer-input" id="textAnswer" value="${escapeHtml(a||"")}" placeholder="Type your answer here"></label>`;else area.innerHTML=`<div class="choice-list">${q.choices.map((c,i)=>`<label class="choice"><input type="radio" name="answer" value="${escapeHtml(c)}" ${a===c?"checked":""}><span><b>${String.fromCharCode(65+i)}.</b> ${c}</span></label>`).join("")}</div>`;$("#lesson").classList.add("hidden");$("#teachButton").textContent=data.profile.voice==="bestie"?"✦ Help bestie, teach me this":"✦ Teach me this topic";$("#progressText").textContent=`${exam.index+1} / ${exam.questions.length}`;$("#progressFill").style.width=`${(exam.index+1)/exam.questions.length*100}%`;$("#prevButton").disabled=exam.index===0;$("#nextButton").textContent=exam.index===exam.questions.length-1?"Submit exam →":"Next question →";$("#questionGrid").innerHTML=exam.questions.map((x,i)=>`<button class="${i===exam.index?"current":exam.answers[x.id]!=null?"answered":""}" data-index="${i}">${i+1}</button>`).join("");$("#questionGrid").querySelectorAll("button").forEach(b=>b.onclick=()=>{exam.index=+b.dataset.index;renderQuestion()});area.querySelectorAll("input").forEach(i=>i.oninput=()=>setAnswer(q.id,i.value))}
function setAnswer(id,val){exam.answers[id]=val;data.draft=exam;save();$("#saveStatus").textContent="Saved ✓";setTimeout(()=>$("#saveStatus").textContent="Answer saves automatically",900)}
function next(){let q=exam.questions[exam.index];if(exam.answers[q.id]==null||exam.answers[q.id]===""){toast("Add an answer before moving on.");return}if(exam.index<exam.questions.length-1){exam.index++;renderQuestion()}else finishExam()}
const COACH_EXAMPLES={
  "Functions":"Example: if f(x)=2x+3, then f(4)=2(4)+3=11. Replace x with the input first.",
  "Quadratics":"Example: x²−5x+6 factors into (x−2)(x−3), so the solutions are 2 and 3.",
  "Complex Numbers":"Example: i⁶ has remainder 2 when divided by 4, so i⁶=i²=−1.",
  "Polynomials":"Example: the remainder of p(x)=x²+1 divided by x−3 is p(3)=10.",
  "Rational Functions":"Example: (x²−9)/(x−3)=(x−3)(x+3)/(x−3)=x+3, but x still cannot equal 3.",
  "Radicals":"Example: √50=√(25·2)=5√2. Pull the square root of the perfect square outside.",
  "Exponential Functions":"Example: 2ˣ=16 becomes 2ˣ=2⁴, so x=4.",
  "Logarithms":"Example: log₂(8)=3 because 2³=8. A log is asking for an exponent.",
  "Exponentials & Logs":"Example: log₂(8)=3 means 2³=8.",
  "Sequences":"Example: for 2,5,8,… the difference is 3, so a₆=2+5(3)=17.",
  "Systems":"Example: set y=x+2 and y=−x+6 equal: x+2=−x+6, so x=2 and y=4.",
  "Trigonometry":"Example: 60°·π/180=π/3 radians."
};
const COACH_FORMULAS={
  "Functions":"For f(a), replace every x in the rule with a.",
  "Quadratics":"Quadratic formula: x=(−b±√(b²−4ac))/(2a). Factoring may be faster when the numbers are friendly.",
  "Complex Numbers":"Powers of i repeat every four: i, −1, −i, 1.",
  "Polynomials":"Remainder Theorem: dividing p(x) by x−a leaves p(a).",
  "Rational Functions":"Factor first. Canceled denominator factors make holes; remaining denominator zeros make vertical asymptotes.",
  "Radicals":"√(a·b)=√a·√b. Look for the largest perfect-square factor.",
  "Exponential Functions":"Typical form: y=a(b)ˣ. If possible, rewrite both sides with the same base.",
  "Logarithms":"logₐ(b)=x means aˣ=b.",
  "Exponentials & Logs":"logₐ(b)=x means aˣ=b.",
  "Sequences":"Arithmetic: aₙ=a₁+(n−1)d. Geometric: aₙ=a₁rⁿ⁻¹.",
  "Systems":"Set equal expressions equal, solve one variable, then substitute back.",
  "Trigonometry":"Degrees to radians: multiply by π/180."
};
function coachReply(q,text){
  let t=text.toLowerCase();
  if(/answer|walk.?through|solve it|full solution/.test(t)){exam.assisted??={};exam.assisted[q.id]=true;return`Let’s walk through this exact question:\n\n${q.explanation}\n\nNow try explaining that last step in your own words—that’s the part that makes it stick.`}
  if(/another|example|different number/.test(t))return`${COACH_EXAMPLES[q.topic]||q.lesson}\n\nTry copying those same steps on the current question.`;
  if(/formula|rule|equation/.test(t))return`${COACH_FORMULAS[q.topic]||q.lesson}\n\nThe important part is choosing the formula first, then substituting carefully.`;
  if(/first|start|hint|next step/.test(t))return`Start here: ${q.lesson}\n\nDo only the first substitution or factoring step before worrying about the final answer.`;
  if(/why|how come/.test(t))return`The reason is that each algebra step must keep both sides equivalent. For this problem: ${q.explanation}`;
  if(/simpl|confus|understand|what does|huh/.test(t))return`Super simple version: ${COACH_FORMULAS[q.topic]||q.lesson}\n\nThink of it as one small job at a time. ${COACH_EXAMPLES[q.topic]||""}`;
  if(/check|my answer|correct/.test(t))return`I can help you check the method without judging the final answer yet. Tell me what your first step was, then compare it with this hint: ${q.lesson}`;
  return`I’m an offline coach, so I’m best at questions about this ${q.topic} problem. Here’s the key idea: ${q.lesson}\n\nTry asking “explain it simpler,” “show another example,” “what’s the first step?”, or “walk me through it.”`;
}
function renderCoach(){
  let q=exam.questions[exam.index],messages=exam.chats?.[q.id]||[];
  $("#lesson").innerHTML=`<div class="coach-head"><div><h3>✦ Offline Study Coach</h3><small>${q.topic} • ask as many follow-ups as you need</small></div><button class="coach-close" type="button" aria-label="Close coach">×</button></div><div class="coach-messages">${messages.map(m=>`<div class="coach-message coach-${m.role}">${escapeHtml(m.text)}</div>`).join("")}</div><div class="coach-quick"><button type="button" data-coach="Explain it simpler">Explain it simpler</button><button type="button" data-coach="What's the first step?">First step</button><button type="button" data-coach="Show another example">Another example</button><button type="button" data-coach="Walk me through it">Full walkthrough</button></div><form class="coach-form"><input id="coachInput" aria-label="Ask the Study Coach" placeholder="Ask a follow-up question…" autocomplete="off"><button>Send</button></form><p class="coach-note">Works offline. It knows this lesson and common follow-ups, but it is not a general internet AI.</p>`;
  $("#lesson").classList.remove("hidden");$(".coach-close").onclick=()=>$("#lesson").classList.add("hidden");$(".coach-form").onsubmit=e=>{e.preventDefault();sendCoach($("#coachInput").value)};$$("[data-coach]").forEach(b=>b.onclick=()=>sendCoach(b.dataset.coach));let box=$(".coach-messages");box.scrollTop=box.scrollHeight;
}
function sendCoach(text){if(!text.trim())return;let q=exam.questions[exam.index];exam.chats??={};exam.chats[q.id]??=[];exam.chats[q.id].push({role:"user",text:text.trim()});exam.chats[q.id].push({role:"bot",text:coachReply(q,text)});data.draft=exam;save();renderCoach()}
function teach(){let q=exam.questions[exam.index];exam.hints[q.id]=true;exam.chats??={};exam.chats[q.id]??=[{role:"bot",text:`Let’s work on this together. ${q.lesson}\n\nWhat part feels confusing? You can keep asking until it makes sense.`}];data.draft=exam;save();renderCoach()}
