function updateTimer(){let m=Math.floor(exam.seconds/60),s=exam.seconds%60;$("#timer strong").textContent=`${m}:${String(s).padStart(2,"0")}`;$("#timer").classList.toggle("urgent",exam.seconds<300)}
function finishExam(timedOut=false){clearInterval(timerId);let correct=0,unassistedCorrect=0,unassistedTotal=0,topics={};exam.questions.forEach(q=>{let ok=isCorrect(q,exam.answers[q.id]);correct+=ok;topics[q.topic]??={correct:0,total:0};topics[q.topic].total++;topics[q.topic].correct+=ok;if(!exam.hints[q.id]){unassistedTotal++;unassistedCorrect+=ok}});Object.values(topics).forEach(t=>t.percent=Math.round(t.correct/t.total*100));let percent=Math.round(correct/exam.questions.length*100),result={id:Date.now(),date:new Date().toISOString(),mode:exam.mode,selectedTopic:exam.selectedTopic,questionCount:exam.questionCount,timeLimitMinutes:exam.timeLimitMinutes,score:correct,total:exam.questions.length,percent,grade:grade(percent),secondsUsed:exam.totalSeconds-exam.seconds,hints:Object.keys(exam.hints).length,assisted:Object.keys(exam.assisted||{}).length,formulaOpens:exam.formulaOpens,unassisted:unassistedTotal?Math.round(unassistedCorrect/unassistedTotal*100):0,topics,answers:exam.answers,hinted:exam.hints,questions:exam.questions.map(q=>q.id),timedOut};data.history.unshift(result);data.draft=null;save();renderResults(result);showView("results")}
function renderResults(r){let bestie=data.profile.voice==="bestie",weak=Object.entries(r.topics).sort((a,b)=>a[1].percent-b[1].percent)[0]?.[0];$("#resultTitle").textContent=bestie?(r.percent>=80?"Okayyy, you cooked.":"Practice data acquired ✨"):"Exam complete.";$("#resultMessage").textContent=bestie?`${data.profile.name}, you scored ${r.percent}%. ${weak} was the spicy bit today, so that’s our next glow-up target.`:`${data.profile.name}, you scored ${r.percent}%. Your next recommended focus is ${weak}.`;$("#resultPercent").textContent=`${r.percent}%`;$("#resultGrade").textContent=r.grade;$(".score-ring").style.setProperty("--score",`${r.percent*3.6}deg`);let mins=Math.floor(r.secondsUsed/60),secs=r.secondsUsed%60;$("#statCards").innerHTML=stats([["Points",`${r.score} / ${r.total}`],["Time used",`${mins}:${String(secs).padStart(2,"0")}`],["Hints / assisted",`${r.hints} / ${r.assisted||0}`],["Unassisted",`${r.unassisted}%`]]);$("#topicBreakdown").innerHTML=Object.entries(r.topics).map(([n,t])=>topicRow(n,t.percent)).join("");$("#nextSteps").innerHTML=Object.entries(r.topics).sort((a,b)=>a[1].percent-b[1].percent).slice(0,3).map(([n,t])=>`<div class="next-step"><strong>${n}</strong><span>${t.percent<60?"Relearn the core method, then try an easier example.":t.percent<80?"Do two focused practice questions.":"Keep it fresh with spaced review."}</span></div>`).join("");$("#reviewList").innerHTML=exam.questions.map((q,i)=>{let a=r.answers[q.id]||"No answer",ok=isCorrect(q,a);return `<div class="review-item"><p class="${ok?"correct-text":"wrong-text"}"><strong>${i+1}. ${ok?"Correct":"Review"} — ${q.topic}</strong></p><p>${q.prompt}</p><p>Your answer: ${escapeHtml(a)} · Correct answer: ${Array.isArray(q.answer)?q.answer[0]:q.answer}</p><p>${q.explanation}</p></div>`}).join("");$("#reviewList").classList.add("hidden");$("#toggleReview").textContent="Show review"}
