function renderDashboard(){let h=data.history,name=data.profile.name||"Student";$("#dashboardTitle").textContent=h.length?`${name}, you're building momentum.`:"Your progress starts here.";let avg=h.length?Math.round(h.reduce((s,x)=>s+x.percent,0)/h.length):0,best=h.length?Math.max(...h.map(x=>x.percent)):0,streak=h.length;$("#dashboardStats").innerHTML=stats([["Exams completed",h.length],["Average score",`${avg}%`],["Personal best",`${best}%`],["Practice streak",`${streak} day${streak===1?"":"s"}`]]);let recent=[...h].slice(0,10).reverse();$("#scoreChart").innerHTML=recent.length?recent.map((r,i)=>`<div class="chart-col"><div class="chart-bar" style="height:${Math.max(r.percent*1.8,5)}px"><span>${r.percent}</span></div>D${h.length-recent.length+i+1}</div>`).join(""):`<p class="fine-print">Complete your first exam to see a trend.</p>`;let aggregate={};h.forEach(r=>Object.entries(r.topics).forEach(([n,t])=>{aggregate[n]??={c:0,n:0};aggregate[n].c+=t.correct;aggregate[n].n+=t.total}));$("#masteryList").innerHTML=Object.keys(aggregate).length?Object.entries(aggregate).sort((a,b)=>a[0].localeCompare(b[0])).map(([n,t])=>topicRow(n,Math.round(t.c/t.n*100))).join(""):`<p class="fine-print">Topic mastery will appear after your first exam.</p>`;$("#historyList").innerHTML=h.length?h.slice(0,8).map((r,i)=>`<div class="history-row"><strong>Exam ${h.length-i}</strong><span>${new Date(r.date).toLocaleDateString()}</span><span>${r.percent}% · ${r.grade}</span></div>`).join(""):`<p class="fine-print">No saved sessions yet. Your results stay on this device.</p>`}
