function uniquePromptCount(questions){return new Set(questions.map(q=>q.prompt)).size}
function renderTopicTests(run=false){let summary=$("#topicTestSummary"),list=$("#topicTestResults");if(!summary||!list)return;if(!run){summary.textContent="Click “Run topic tests” to check the app.";list.innerHTML="";return}let originalLog=JSON.parse(JSON.stringify(data.generatorLog||{})),topics=allTopics(),results=[];try{results.push(topicTestResult("Topic list includes all Algebra 2 subjects",topics.length===11,`${topics.length} topics found`));for(let topic of topics){let qs=chooseTopicQuestions(topic,12,"Warm-up",{remember:false});results.push(topicTestResult(`${topic}: creates 12 unique questions`,qs.length===12&&uniquePromptCount(qs)===12,`${uniquePromptCount(qs)} unique prompts`));results.push(topicTestResult(`${topic}: keeps questions in the selected topic`,qs.every(q=>q.topic===topic),qs.map(q=>q.topic).filter(t=>t!==topic).join(", ")||"all matched"));results.push(topicTestResult(`${topic}: questions have answers and explanations`,qs.every(q=>q.answer&&q.lesson&&q.explanation&&q.prompt),"shape check"))}for(let topic of topics){data.generatorLog={usedPromptKeys:[],sessionCounter:0};let first=chooseTopicQuestions(topic,10,"Medium"),second=chooseTopicQuestions(topic,10,"Medium"),secondPrompts=new Set(second.map(q=>q.prompt)),overlap=first.filter(q=>secondPrompts.has(q.prompt));results.push(topicTestResult(`${topic}: back-to-back tests do not repeat`,overlap.length===0,`${overlap.length} repeats`))}data.generatorLog={usedPromptKeys:[],sessionCounter:0};let exponents=chooseTopicQuestions("Exponential Functions",25,"Warm-up",{remember:false}),logLeak=exponents.find(q=>/log/i.test(`${q.prompt} ${q.lesson} ${q.explanation}`));results.push(topicTestResult("Exponential Functions does not include logs",!logLeak,logLeak?.prompt||"clean"));let logs=chooseTopicQuestions("Logarithms",12,"Warm-up",{remember:false});results.push(topicTestResult("Logarithms includes actual log questions",logs.some(q=>/log base/i.test(q.prompt)),"log prompt check"));let mix=chooseQuestions();results.push(topicTestResult("Adaptive mix creates 10 unique questions",mix.length===10&&uniquePromptCount(mix)===10,`${uniquePromptCount(mix)} unique prompts`))}catch(error){results.push(topicTestResult("Test runner crashed",false,error.message))}finally{data.generatorLog=originalLog;save()}let passed=results.filter(r=>r.pass).length;summary.textContent=`${passed} / ${results.length} tests passed.`;summary.className=`test-summary ${passed===results.length?"test-pass":"test-fail"}`;list.innerHTML=results.map(r=>`<div class="test-row ${r.pass?"test-pass":"test-fail"}"><strong>${r.pass?"✓":"✕"} ${escapeHtml(r.name)}</strong><span>${escapeHtml(r.detail)}</span></div>`).join("")}
