async function applySignedInUser(user){authUser=user;if(accountUnsub){accountUnsub();accountUnsub=null}if(!user){account=null;renderAccount();forceAuthGate(true);return}forceAuthGate(false);account=await firestoreSyncAccount();renderAccount();let ref=fb.firestore().collection("users").doc(user.uid);accountUnsub=ref.onSnapshot(snap=>{if(snap.exists){account={uid:user.uid,...snap.data()};renderAccount();let premium=account?.accountType==="premium"||account?.premiumStatus==="approved"||isAdminEmail(user.email);showAuthMessage(`${premium?"Premium/Admin":"Basic"} account loaded for ${user.email}.`)}});let premium=account?.accountType==="premium"||account?.premiumStatus==="approved"||isAdminEmail(user.email);toast(`${premium?"Premium/Admin":"Basic"} signed in`)}
